  if (from == to) return;

  _isTransitioning = true;
  notifyListeners();

  if (from is num && to is num) {
    _animatedParams[id] = _AnimatedValue<double>(
      from: from.toDouble(),
      to: to.toDouble(),
      duration: parameterDuration,
      curve: curve,
      onComplete: () {
        _animatedParams.remove(id);
        _checkTransitionComplete();
      },
    );
  } else if (from is int && to is int) {
    _animatedParams[id] = _AnimatedValue<double>(
      from: from.toDouble(),
      to: to.toDouble(),
      duration: parameterDuration,
      curve: curve,
      onComplete: () {
        _animatedParams.remove(id);
        _checkTransitionComplete();
      },
    );
  }

  notifyListeners();
}

